class NordicIslandsError extends Error {
  /**
   * @param { string } message
   * @param { { type: string, path: string } } [file]
   * @param { Error } [originalError]
   */
  constructor(message, file, originalError) {
    super(message, {
      cause:
        originalError instanceof NordicIslandsError
          ? originalError.cause
          : originalError,
    });

    /** @type { string } */
    this.stack = this.#getStack(message, file, originalError);
  }

  #getStack(message, file, originalError) {
    if (originalError instanceof NordicIslandsError) {
      return originalError.stack;
    }

    return `[Nordic Islands] ${message}\n${
      file ? `  at ${file.type} (${file.path})\n` : ''
    }${originalError ? `  ${originalError.stack}` : ''}`;
  }
}

module.exports = {
  NordicIslandsError,
};
